namespace InventoryApp.Services;

public record EquipmentItem(
    int Id,
    string Name,
    string Location,
    DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database / API call
        await Task.Delay(400);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press #7",    "Building A – Bay 3",  new DateTime(2026, 4, 12)),
            new(2, "CNC Lathe L-200",       "Building B – Shop 1", new DateTime(2026, 3, 28)),
            new(3, "Overhead Crane OC-14",   "Building A – Bay 1",  new DateTime(2026, 5, 1)),
            new(4, "Arc Welder AW-50",       "Building C – Weld Lab",new DateTime(2026, 2, 15)),
            new(5, "Forklift FL-009",        "Warehouse D",         new DateTime(2026, 5, 20)),
            new(6, "Band Saw BS-320",        "Building B – Shop 2", new DateTime(2025, 12, 10)),
            new(7, "Compressor CP-800",      "Utility Room 2",      new DateTime(2026, 1, 22)),
            new(8, "Drill Press DP-44",      "Building A – Bay 5",  new DateTime(2026, 4, 30)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState PersistentState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // During the interactive re-initialization, restore persisted data
        // instead of calling the service a second time.
        if (PersistentState.TryTakeFromJson<List<EquipmentItem>>(
                nameof(_items), out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentService.GetEquipmentAsync();
        }

        // During prerender, register the data so it can be shipped to the client.
        _persistSub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson(nameof(_items), _items);
            return Task.CompletedTask;
        });
    }

    public void Dispose() => _persistSub.Dispose();
}

